mapper.select:
SELECT DATE_FORMAT(rdm.ts, '%Y-%m-%d %H:%i') AS x , zn.zone_name, ROUND(SUM(rdm.VALUE*pti.PWI_UNIT_VALUE),2) AS y FROM TB_RAWDATA_15MIN rdm, TB_TAGINFO ti, TB_ZONE zn, TB_PEAK_TAG_INF pti where rdm.ts >= DATE_FORMAT(now(), '%Y-%m-%d 00:00:00') AND rdm.ts <= DATE_FORMAT(now(), '%Y-%m-%d 23:59:00') AND rdm.tagname = ti.tagname AND ti.zone_code = zn.zone_code AND pti.PWI_TAG = ti.tagname AND ti.USE_YN = '1' and pti.mntr_yn = '1'
AND zn.zone_code = #{zone_code}
GROUP BY rdm.ts, zn.zone_name ORDER BY zn.zone_name, rdm.ts
